sql:
SELECT city_name, state, latitude
FROM cities
WHERE population = (SELECT MAX(population) FROM cities);

SELECT report_id, status
FROM reports
WHERE year <= 2020 AND crime_type_id = 0;

SELECT hotspot_id, hotspot_value
FROM crime_hotspots
WHERE hotspot_value > (SELECT AVG(hotspot_value) FROM crime_hotspots);

SELECT crime_type_id, AVG(trend_value) AS average_trend_value
FROM crime_trends
GROUP BY crime_type_id;

external_knowledge:
- 'crime_type_id = 0' represents a specific crime type according to the database schema;
- 'law enforcement team' refers to users with the role 'law enforcement';
- 'downloaded' specifically refers to the 'download' access type in the database.

sql:
SELECT year, COUNT(*) AS total_visualizations
FROM data_visualizations
GROUP BY year;

SELECT city_name
   FROM cities
   WHERE city_name = 'Andover';

SELECT user_name AS name FROM users WHERE role = 'law enforcement'
UNION
SELECT crime_type_name AS name FROM crime_types WHERE severity_level = 'high';

SELECT role_name, created_at, last_updated
FROM users_roles
WHERE role_name = 'analyst';
